diff --git a/llvm/lib/Transforms/InstCombine/InstCombineMulDivRem.cpp b/llvm/lib/Transforms/InstCombine/InstCombineMulDivRem.cpp
index 8d5866e98a8e..af3b86410027 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineMulDivRem.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineMulDivRem.cpp
@@ -486,6 +486,19 @@ Instruction *InstCombinerImpl::visitMul(BinaryOperator &I) {
                             m_c_Mul(m_UMax(m_Value(X), m_Value(Y)),
                                     m_c_UMin(m_Deferred(X), m_Deferred(Y))))))
     return BinaryOperator::CreateWithCopiedFlags(Instruction::Mul, X, Y, &I);
+  // (select c, X, Y) * (select c, Y, X) --> X * Y
+  // When both selects have the same condition with swapped arms, the result is
+  // always X * Y regardless of the condition.
+  if (auto *Sel0 = dyn_cast<SelectInst>(Op0)) {
+    if (auto *Sel1 = dyn_cast<SelectInst>(Op1)) {
+      if (Sel0->getCondition() == Sel1->getCondition() &&
+          Sel0->getTrueValue() == Sel1->getFalseValue() &&
+          Sel0->getFalseValue() == Sel1->getTrueValue()) {
+        return BinaryOperator::CreateWithCopiedFlags(
+            Instruction::Mul, Sel0->getTrueValue(), Sel0->getFalseValue(), &I);
+      }
+    }
+  }

   // (mul Op0 Op1):
   //    if Log2(Op0) folds away ->
diff --git a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
index f072f5cec309..aaabae3c8b59 100644
--- a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
@@ -1132,6 +1132,11 @@ Value *InstCombinerImpl::SimplifySelectsFeedingBinaryOp(BinaryOperator &I,
   };

   if (LHSIsSelect && RHSIsSelect && A == D) {
+    // (A ? B : C) op (A ? C : B) -> B op C (when op is commutative)
+    // This handles the case where the two selects have swapped arms.
+    if (I.isCommutative() && B == F && C == E) {
+      return Builder.CreateBinOp(Opcode, B, C, I.getName());
+    }
     // (A ? B : C) op (A ? E : F) -> A ? (B op E) : (C op F)
     Cond = A;
     True = simplifyBinOp(Opcode, B, E, FMF, Q);

